INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (46, 'IT''s Your life에 지원하신 동기와 과정 수료 후, 이루고 싶은 취업계획을 작성해 주십시오.', 0, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (46, '[SW비전공] 2-1. SW에 관심을 가지게 된 계기 혹은 취업 준비를 하며 겪었던 경험에 대해 작성하고, IT''s Your Life 과정을 통해 향후 어떤 개발자로 성장하고 싶은지 작성해 주십시오.', 1, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (46, '[SW전공] 2-2. SW 관련 경험 중 어려웠던 과제와 해결 방안에 대해 작성하고, IT''s Your Life 과정을 통해 향후 어떤 개발자로 성장하고 싶은지 작성해 주십시오. ※ SW 관련 경험 : SW 개발, SW 프로젝트 및 경진대회 경험(참여, 수상 등), IT 관련 자격증 취득 등', 2, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (47, '마케터로서 그리고 있는 커리어 방향은 무엇인가요? 퍼포먼스 마케터 직무에 관심을 갖게 된 계기가 있다면 함께 적어주세요.', 0, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (47, '팀민트에서 일하며 경험해보고 싶은 성장 포인트는 무엇인가요? 또한 신입으로서 팀에 기여할 수 있다고 생각하는 부분이 있다면 함께 적어주세요.', 1, 500);
