INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (87, '팀워크를 발휘해 사람들은 연결하고 공동 목표 달성에 기여한 경험이 있다면 서술해 주십시오.', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (87, '지원하신 직무 분야의 전문성을 키우기 위해 꾸준히 노력한 경험에 대해 서술해 주세요.', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (87, '지원자님은 어떤 사람인가요? 본 문항은 자유롭게 여러분을 표현할 수 있는 자율 문항입니다. 지원자님을 가장 잘 나타낼 수 있는 해시태그(#)를 포함하여, 남들과는 다른 특별한 가치관, 개성, 강점 등을 자유롭게 표현해주세요.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (87, '자발적으로 최고 수준의 목표를 세우고 끈질기게 성취한 경험에 대해 서술해 주십시오.', 3, 1000);
