INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (91, '이노션 지원동기 및 지원 분야에 대한 업무 전문성을 작성해주세요. (최소 100자 ~ 최대 1,000자)', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (93, '큐알티 지원 동기와 본인의 어떤 특성이 잘 부합하는지 사례를 들어 상세히 기술하여 주십시오. (500자 이상)', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (93, '본인이 살아오면서 가장 강렬히 성취하고 싶었던 일은 무엇입니까?  그 일을 성취하고 싶었던 이유, 이를 달성하기 위해 했던 일, 그리고 그 결과와 느꼈던 점을 포함하여 상세히 기술하여 주십시오 (500자 이상)', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (93, '다른 사람과 함께 일(경험)을 했을 때 그 사람은 귀하를 어떻게 판단했고, 귀하는 그 사람을 어떻게 판단했는지 구체적인 사례와 이유를 들어 설명해 주십시오 (500자 이상)', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (93, '이제까지 강한 소속감을 느낀 조직은 무엇이며, 그 조직의 발전을 위해 헌신적으로 노력한 것 중 가장 기억에 남는 경험은 무엇인지 구체적인 사례와 이유를 들어 설명해 주십시오 (500자 이상)', 3, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (93, '지원 분야에 가장 중요한 실무 역량은 무엇이라고 생각하는지 정의하고, 그에 따라 본인의 역량 수준을 점수화(100점 만점 기준)하여 주시기 바랍니다. 그리고 본인이 현재의 역량을 보유하기 위해 과거에 어떤 노력을 하였는지 사례를 들어 상세히 기술하여 주십시오. (500자 이상)', 4, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (93, '괄호 안에 제시된 키워드 중 본인을 가장 잘 표현하거나, 혹은 본인이 추구하는 바와 가장 유사한 2가지를 선정하고 그 이유를 설명하여 주십시오 (500자 이상)', 5, 1000);
