INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (97, '지원 분야에 가장 중요한 실무 역량은 무엇이라고 생각하는지 정의하고, 그에 따라 본인의 역량 수준을 점수화(100점 만점 기준)하여 주시기 바랍니다. 그리고 본인이 현재의 역량을 보유하기 위해 과거에 어떤 노력을 하였는지 사례를 들어 상세히 기술하여 주십시오. (500자 이상)', 10, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (97, '괄호 안에 제시된 키워드 중 본인을 가장 잘 표현하거나, 혹은 본인이 추구하는 바와 가장 유사한 2가지를 선정하고 그 이유를 설명하여 주십시오 (500자 이상)', 11, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (98, '큐알티 지원 동기와 본인의 어떤 특성이 잘 부합하는지 사례를 들어 상세히 기술하여 주십시오. (500자 이상)', 0, 1000);
