INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (138, '본인이 생각하는 회사를 선택하는 기준을 바탕으로 앰코코리아가 왜 그 기준에 적합한지 구체적으로 서술해 주시기 바랍니다.', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (138, '해당 직무에 지원한 지원동기 및 다른 지원자보다 해당 직무를 더 잘 수행할 수 있는 이유를 구체적으로 서술해 주시기 바랍니다.', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (138, '본인이 극복했던 문제나 어려움 중 가장 슬기롭게 해결한 것은 어떤 것이며, 해결 상황을 구체적으로 서술해 주시기 바랍니다.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (139, '(*필수) [자기소개] AI 및 SW분야의 전문성을 키우기 위해 몰입했던 경험과 도전이 무엇인지, 또한 이러한 성장과정을 통해 얻은 배움은 무엇인지를 서술하여 주시기 바랍니다.(최소 400자, 최대 1000자 입력가능)', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (139, '(*필수) [연수계획서] AI·SW마에스트로 과정 참여를 통해 어떠한 프로젝트를 수행하고 싶은가요? 해당 프로젝트를 수행하기 위한 계획과 이루고자 하는 목표가 무엇인지 구체적으로 서술하여 주시기 바랍니다.(최소 400자, 최대 1000자 입력가능)', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (139, '(선택) AI 및 SW대회 수상 등 증빙이 가능한 경우 서술하여 주시기 바랍니다. (대회명 / 수상내역 / 수상일자 / 수여기관 / 증빙서(첨부파일))', 2, 1000);
