INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (179, '1.지원분야 업무에 있어 가장 중요하다고 생각하는 ''안전 관련 역량''은 무엇이며, 해당 역 량을 강화하기 위해 노력했던 경험을 구체적으로 작성해 주십시오.', 0, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (179, '2.상대방의 입장에서 상황을 분석하고, 요구사항 이면의 필요를 파악하여 기대 이상의 결과를 만들어낸 경험을 구체적으로 작성해 주십시오.', 1, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (179, '3.기존의 업무방식이나 관행에 문제의식을 가지고, 더 나은 결과를 위해 새로운 시도나 도전 을 추진했던 경험에 대해 구체적으로 작성해 주십시오.', 2, 600);
