INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (206, '2. 에이피알이 지향하는 4가지 인재상(Make it, Grow up, Work Together, Customer Success) 중에서 하나를 선택하고, 해당 핵심가치와 부합하는 경험 또는 성과를 구체적으로 작성해주세요(글자수 제한 없음)', 1, 10000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (206, '3. 에이피알에 지원한 동기와 입사 후 이루고자 하는 목표 및 포부를 작성해주세요(글자수 제한 없음)', 2, 10000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (207, '자신의 성장과정', 0, 600);
