INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (233, '지금까지 가장 많은 노력을 쏟아부었던 성공 혹은 실패 경험과 그 과정을 통해 무엇을 배웠는지 작성해주세요.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (233, '경력기술서를 작성해주세요. (퇴직사유 포함) 신입의 경우 ''해당없음''으로 작성해주세요.', 3, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (236, '자신의 성장과정과 학창시절을 간략하게 소개하여 주십시오.', 0, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (236, '울산알루미늄에 지원하신 동기와 지원하신 분야의 직무를 잘 수행하기 위하여 어떤 준비를 했는지 본인의 경험과 관련하여 기술해 주십시오.', 1, 700);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (236, '자신의 성격의 장,단점 및 단점을 극복하기 위해 어떤 노력을 했는지 기술해 주십시오.', 2, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (236, '새로운 환경이나 팀 내에서 어려운 과제에 직면했던 경험은 무엇이고, 이를 어떻게 해결 했는지 실제 사례를 예시로 하여 작성해 주십시오.', 3, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (237, '파주에너지서비스의 어떤 부분에 대해 관심을 가지고 지원하게 되었으며, 입사 후 어떻게 기여하고 싶은지 본인의 강점을 기반으로 작성해 주십시오.', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (237, '지원 직무와 관련하여, 학교/사회생활을 통해 본인의 전문성 및 역량 개발에 도움이 되었던 경험, 경력, 활동을 먼저 서술하고 지원 직무를 수행하는데 어떻게 활용(도움)될 수 있는지 작성해 주십시오.', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (237, '어려웠던 문제나 상황을 자발적, 의욕적으로 스스로 끝까지 완수했던 경험을 작성해 주십시오.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (237, '타인과의 소통/설득을 통해 협력을 최대한 이끌어 내어, 가치 있는 결과를 성취하였던 경험에 대해 서술해 주십시오.', 3, 1000);
