INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (270, '[논리성] 1. 지원동기와 근무하는 기간 동안에 이루고자하는 목표에 대해 기술하여주십시오.', 0, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (270, '[전문성] 2. 지원 직무를 수행하기 위해 필요한 역량이 무엇이며, 이와 관련한 본인의 역량에 대해 구체적 사례를 중심으로 기술해주십시오.', 1, 600);
