INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (270, '[사회성] 4. 구성원간 갈등 상황에서 의사소통을 통해 업무(프로젝트 등)를 효율적으로 수행하도록 노력했던 경험과 효과적인 의사소통 방법에 대해 기술하여 주십시오.', 3, 600);
