INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (279, '[역량기술서] 경력사항 및 직무관련 기타 활동 란에 작성한 내용에 대해 상세히 기술해 주시기 바랍니다.', 4, 2000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (280, '[의사소통·문제해결능력] 1. 조직 또는 학교에서 공동의 목표를 달성하는 과정에서 생긴 어려움은 무엇이며, 그 어려움을 극복하기 위한 노력을 구체적으로 기술해주십시오.', 0, 700);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (280, '[조직이해·직업윤리능력] 2. 우리 원에 지원한 동기 및 입사 후 실천하고자 하는 목표와 우리 원에 근무하는 사람에게 가장 필요한 덕목을 기술해주십시오.', 1, 700);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (280, '[대인관계능력] 3. 약속과 원칙을 지켜 신뢰를 형성하고, 유지했던 경험에 대해 기술해주십시오.', 2, 700);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (280, '[자기개발능력] 4. 현재 자신의 위치에 오기 위해 수행해 온 노력과 앞으로의 계획을 기술해주십시오.', 3, 700);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (280, '[역량기술서] 경력사항 및 직무관련 기타 활동 란에 작성한 내용에 대해 상세히 기술해 주시기 바랍니다.', 4, 2000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (281, '주요 경력사항/담당 직무 위주로 기술(회사, 연도, 기간, 담당직무 등)', 0, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (281, '보유 기술/특기/주요 자격사항/어학 능력/해외 연수 경험 기술', 1, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (281, '지원동기/회사 기여 가능성 등 포부 기술', 2, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (282, '현대종합금속 및 지원 직무에 대한 지원 동기와 입사 후 성취하고 싶은 목표를 작성해주시기 바랍니다. (자신의 전공, 경험, 역량 활용 계획)', 0, 800);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (282, '현대종합금속의 인재상 (창의, 팀워크, 용기, 도전) 중, 자신에게 가장 부합하는 항목을 선택하고, 이를 바탕으로 어려움을 극복한 사례를 구체적으로 작성해주시기 바랍니다.', 1, 800);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (282, '지원하는 직무에 있어 본인만의 차별화된 역량이 무엇인지, 그리고 이를 발전시키기 위해 노력한 경험을 상세히 기술해 주십시오.', 2, 800);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (282, '본인의 성장과정 및 성격의 장단점을 간략하게 작성해 주십시오.', 3, 800);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (282, '직무와 연관된 경력 기술을 키워드별로 간략하게 작성해 주십시오. *신입 지원의 경우, 직무와 연관된 경험 작성.', 4, 500);
