INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (354, '1. 프리윌린 세일즈팀에 지원하게 된 동기를 구체적으로 서술해 주세요. (글자수 제한 없음)', 0, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (354, '2. 지원한 포지션을 성공적으로 수행할 수 있는 이유를 보유한 역량과 경험을 바탕으로 서술해 주세요. (글자수 제한 없음)', 1, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (354, '3. 스타트업인 프리윌린은 어떤 특징이 있는 회사라고 생각하는지 서술하시고, 본인이 어떤 점에서 회사와 잘 어울릴 수 있을지 경험을 바탕으로 작성해 주세요. (글자수 제한 없음)', 2, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (354, '4. 고객 대응 업무 진행 시, 본인이 가장 강점이라고 생각하는 점과 앞으로 보완하고 싶은 점을 작성해 주세요. (글자수 제한 없음)', 3, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (355, '1. 프리윌린의 ‘풀리캠퍼스’는 대학을 주요 고객으로 하는 교육 플랫폼입니다. 풀리캠퍼스 서비스에 대한 내용들을 참고하여, 대학교(교수님, 행정 담당자 등)에게 풀리캠퍼스를 제안할 때 강조할 셀링 포인트를 작성해주세요.', 0, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (355, '2. 풀리 서비스 세일즈를 성공적으로 수행할 수 있다고 생각하는 이유를 본인의 경험과 역량을 바탕으로 구체적으로 작성해주세요.', 1, 5000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (355, '3. 본인이 경험했던 가장 어려웠던 경험은 무엇이었으며, 그 경험을 어떻게 극복하고 성장하셨는지 사례를 들어 작성해주세요.', 2, 5000);
