INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (399, 'GC Cell에 지원한 이유와 입사 후 이루고 싶은 목표에 대해 작성해 주세요.', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (399, '해당 직무를 지원한 이유와 지원 직무와 관련된 본인의 경쟁력이 무엇인지 작성해 주세요.', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (399, '구성원들과 협업했던 과정에서 갈등 또는 어려움을 겪었던 과정을 작성하고, 이를 해결하기 위해 노력했던 경험을 작성해 주세요.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (399, '위 문항에서 다루지 못한 본인의 차별화된 강점 또는 GC셀에서 발휘하고 싶은 역량에 대해 자유롭게 작성해 주세요.', 3, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (400, '지원 동기', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (400, '연구분야 및 연구역량 (대표적 실적 및 경력 / 행정직의 경우, 행정 업무관련 경력 및 역량 등을 중심으로 작성)', 1, 2000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (400, '업무계획', 2, 2000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (400, '기타 (참고 할 만한 사항에 대해 자유롭게 기재)', 3, 2000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (402, '1. 본인을 자유롭게 설명해주세요. (성장과정, 학창시절, 성격, 장단점 등)', 0, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (402, '2. 당 회에 지원한 이유와 희망하는 업무 및 그 이유에 대해 서술하고, 이를 위해 본인이 갖춘 차별화된 역량도 서술하세요.', 1, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (402, '3. 팀 또는 단체에 속하여 활동할 때 해당 집단의 목표 달성에 기여하는 자신만의 방식을 본인 경험에 근거하여 자유롭게 기재하여 주세요.', 2, 600);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (402, '4. 저축은행을 직ㆍ간접적으로 경험한 사례를 이야기하고, 본인이 생각하는 저축은행에 대해 자유롭게 기재하여 주세요.', 3, 600);
