INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (412, '다양한 사람들이 있는 집단/조직에서 원활한 의사소통을 바탕으로 함께 문제를 해결하고, 지원자의 성과를 인정받은 경험에 대해서 기술하세요.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (412, '공공기관 직원으로서 가장 중요하게 여겨야하는 가치는 무엇이며, 해당 가치를 진흥원에서 어떻게 실천할 것인지 지원동기와 함께 기술하세요.', 3, 1000);
