INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (414, '[1-1] 성장과정:가족사항, 학창시절, 교우관계, 생활습관, 자신에게 크게 영향을 미친 사건 등을 포함하여 구체적으로 작성 (최대 500자)', 0, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (414, '[1-2] 실패 혹은 좌절을 극복한 사례와 이를 통해 얻은 교훈은? (최대 300자)', 1, 300);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (414, '[2-1] 증권업을 선택하게된 이유와 증권사 중 당사를 선택한 이유 (최대 300자)', 2, 300);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (414, '[2-2] 지원한 분야는 어떤 일을 한다고 생각하는가? (최대 200자)', 3, 200);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (414, '[2-3] 지원분야에 본인이 적합한 이유를 증명하시오. (최대 500자)', 4, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (414, '[3] 당신의 인생계획(Life Plan)에서 꿈은 무엇이고, 그 꿈을 이루기 위해 회사가 어떻게 도움을 줄 수 있는지 서술하시오. (최대 500자)', 5, 500);
