INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (421, '기술보증기금 전문체육선수 지원 동기 및 지원자의 장단점에 대해 기술해주십시오.(500자 이내)', 0, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (421, '지원자는 장애를 극복하기 위해 어떠한 노력을 하였고, 이러한 노력이 전문체육선수 활동시 어떻게 도움이 될지 기술해주십시오.(500자 이내)', 1, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (421, '지원자가 살아오면서 공공의 이익을 위해 노력한 사례가 있다면 기술해주십시오.(500자 이내)', 2, 500);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (422, '자신에 대해 자유롭게 표현해 보세요.', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (423, '이엔에프테크놀로지에 지원한 이유를 설명해주세요. 우리 회사에 대해 어떻게 알고 지원했으며, 본인이 회사를 선택할 때 중요하게 생각하는 것은 무엇입니까?', 0, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (423, '해당 직무에 지원한 이유를 설명해주세요. 본인의 전공 및 해당 분야의 경력을 선택한 이유는 무엇입니까?', 1, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (423, '공동과제나 팀 프로젝트를 수행할 때, 동료 간에 의견이 서로 상충되었던 경험에 대해 이야기 해주세요. 갈등이 발생한 이유와 그때 느꼈던 감정, 가장 어려웠던 점과 그것을 극복하기 위해 했던 행동과 생각, 결과에 대해 구체적으로 작성해 주세요.', 2, 1000);
INSERT INTO question (recruitment_id, content, order_val, char_max) VALUES (423, '본인이 관심을 가지고 있는 분야/기술/서비스 등이 있다면 소개해주세요. 왜 이 분야에 관심을 가지게 되었으며 어떤 관련 활동을 하고 있는지, 이에 대해 본인이 가진 목표나 계획은 무엇인지 구체적으로 소개해 주세요.', 3, 1000);
